    "startFrame": 29187,
    "durationSec": 5.205333333333333,
    "durationFrames": 156,
    "speaker": "ずんだもん",
    "text": "人間もチンパンジーもゴキブリもバクテリアも、みんな生命の木の枝なのだ。",
    "speakerColor": "#22c55e",
    "sceneId": 24,
