    "startFrame": 29533,
    "durationSec": 2.538666666666667,
    "durationFrames": 76,
    "speaker": "めたん",
    "text": "全部つながっている、ということですわね。",
    "speakerColor": "#d6336c",
    "sceneId": 24,
    "sceneTitle": "ダーウィンが本当に伝えたかったこと"
